import * as React from "react"
import * as TabsPrimitive from "@radix-ui/react-tabs"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import "./tabs.css"

/* ------------------------------------------------------------------ */
/*  Context                                                            */
/* ------------------------------------------------------------------ */

type TabsVariant = "underline" | "pill"

const TabsContext = React.createContext<{
  variant: TabsVariant
  size: "sm" | "md"
}>({ variant: "underline", size: "md" })

/* ------------------------------------------------------------------ */
/*  CVA                                                                */
/* ------------------------------------------------------------------ */

const tabsListVariants = cva("tabs-list inline-flex items-center", {
  variants: {
    variant: {
      underline: "tabs-list-underline gap-[var(--layout-gap-lg)]",
      pill: "tabs-list-pill w-fit gap-[var(--layout-gap-xs)] p-[var(--layout-padding-2xs)] rounded-[var(--layout-radius-lg)]",
    },
  },
  defaultVariants: {
    variant: "underline",
  },
})

const tabsTriggerVariants = cva(
  "tabs-trigger inline-flex items-center justify-center whitespace-nowrap font-accent cursor-pointer",
  {
    variants: {
      variant: {
        underline: "tabs-trigger-underline",
        pill: "tabs-trigger-pill rounded-[var(--layout-radius-md)]",
      },
      size: {
        sm: "h-[var(--layout-size-lg)] px-[var(--layout-padding-xs)] text-content-caption",
        md: "h-[var(--layout-size-xl)] px-[var(--layout-padding-md)] text-content-note",
      },
    },
    compoundVariants: [
      { variant: "pill", size: "sm", className: "h-[var(--layout-size-md)]" },
      { variant: "pill", size: "md", className: "h-[var(--layout-size-lg)]" },
    ],
    defaultVariants: {
      variant: "underline",
      size: "md",
    },
  }
)

/* ------------------------------------------------------------------ */
/*  Tabs                                                               */
/* ------------------------------------------------------------------ */

function Tabs({
  className,
  variant = "underline",
  size = "md",
  ...props
}: React.ComponentProps<typeof TabsPrimitive.Root> & {
  variant?: TabsVariant
  size?: "sm" | "md"
}) {
  return (
    <TabsContext.Provider value={{ variant, size }}>
      <TabsPrimitive.Root
        data-slot="tabs"
        className={cn("flex flex-col gap-[var(--layout-gap-xl)]", className)}
        {...props}
      />
    </TabsContext.Provider>
  )
}

/* ------------------------------------------------------------------ */
/*  TabsList                                                           */
/* ------------------------------------------------------------------ */

function TabsList({
  className,
  ...props
}: React.ComponentProps<typeof TabsPrimitive.List>) {
  const { variant } = React.useContext(TabsContext)
  return (
    <TabsPrimitive.List
      data-slot="tabs-list"
      className={cn(tabsListVariants({ variant, className }))}
      {...props}
    />
  )
}

/* ------------------------------------------------------------------ */
/*  TabsTrigger                                                        */
/* ------------------------------------------------------------------ */

function TabsTrigger({
  className,
  ...props
}: React.ComponentProps<typeof TabsPrimitive.Trigger>) {
  const { variant, size } = React.useContext(TabsContext)
  return (
    <TabsPrimitive.Trigger
      data-slot="tabs-trigger"
      className={cn(tabsTriggerVariants({ variant, size, className }))}
      {...props}
    />
  )
}

/* ------------------------------------------------------------------ */
/*  TabsContent                                                        */
/* ------------------------------------------------------------------ */

function TabsContent({
  className,
  ...props
}: React.ComponentProps<typeof TabsPrimitive.Content>) {
  return (
    <TabsPrimitive.Content
      data-slot="tabs-content"
      className={cn("tabs-content", className)}
      {...props}
    />
  )
}

export {
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  tabsListVariants,
  tabsTriggerVariants,
}

/* ================================================================
 * TABS — Variant & State Styles
 * Structure (flex, height, gap, radius) lives in tabs.tsx via cva.
 * Theming (colors, borders, states) lives here via tokens.
 * ================================================================ */

/* --------------------------------
 * Transition
 * -------------------------------- */
@media (prefers-reduced-motion: no-preference) {
  .tabs-trigger {
    transition:
      color 150ms ease,
      background 150ms ease,
      border-color 150ms ease,
      box-shadow 150ms ease;
  }
}

/* ================================
 * UNDERLINE variant
 * ================================ */

/* List — bottom border */
.tabs-list-underline {
  border-bottom: var(--layout-border-thin) solid var(--border-default);
}

/* Trigger — base */
.tabs-trigger-underline {
  position: relative;
  color: var(--text-base-moderate);
  border-bottom: var(--layout-border-thick) solid transparent;
  margin-bottom: calc(-1 * var(--layout-border-thin));
}

.tabs-trigger-underline:hover {
  color: var(--text-base-strong);
}

/* Trigger — active */
.tabs-trigger-underline[data-state="active"] {
  color: var(--text-base-strong);
  border-bottom-color: var(--border-selected);
}

/* Trigger — disabled */
.tabs-trigger-underline:disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
  pointer-events: none;
}

/* ================================
 * PILL variant
 * ================================ */

/* List — container background */
.tabs-list-pill {
  background: var(--background-neutral-lighter-default);
}

/* Trigger — base */
.tabs-trigger-pill {
  color: var(--text-base-moderate);
}

.tabs-trigger-pill:hover {
  color: var(--text-base-strong);
}

/* Trigger — active (light: white pops from gray container, dark: lighter shade elevates) */
.tabs-trigger-pill[data-state="active"] {
  background: var(--background-neutral-faint-default);
  color: var(--text-base-strong);
  box-shadow:
    0 1px 2px var(--shadow-neutral-strong),
    0 0 1px var(--shadow-neutral-strong);
}

.dark .tabs-trigger-pill[data-state="active"] {
  background: var(--background-neutral-medium-default);
}

/* Trigger — disabled */
.tabs-trigger-pill:disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
  pointer-events: none;
}

/* ================================
 * Focus ring (both variants)
 * ================================ */
.tabs-trigger:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--background-base), 0 0 0 4px var(--border-selected);
}

/* Pill active + focus needs combined shadow */
.tabs-trigger-pill[data-state="active"]:focus-visible {
  box-shadow:
    0 1px 2px var(--shadow-neutral-strong),
    0 0 1px var(--shadow-neutral-strong),
    0 0 0 2px var(--background-neutral-faint-default),
    0 0 0 4px var(--border-selected);
}

.dark .tabs-trigger-pill[data-state="active"]:focus-visible {
  box-shadow:
    0 1px 2px var(--shadow-neutral-strong),
    0 0 1px var(--shadow-neutral-strong),
    0 0 0 2px var(--background-neutral-medium-default),
    0 0 0 4px var(--border-selected);
}

/* ================================
 * Content
 * ================================ */
.tabs-content:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--background-base), 0 0 0 4px var(--border-selected);
  border-radius: var(--layout-radius-md);
}
